import { ApiVersion, Comparable, Component } from '@ohos/sdkmanager-common';
import { Equals } from '../util/object-unique-map';
export interface HosComponent extends Component {
    getHosSdkVersion(): HosSdkVersion;
    getStage(): string;
}
export interface HosSdkVersion extends Comparable<HosSdkVersion>, Equals<HosSdkVersion> {
    getPlatformVersion(): PlatformVersion;
    /**
     * @deprecated 请使用`getFullBaseApi()`替代
     */
    getBaseApi(): number;
    getFullBaseApi(): ApiVersion;
}
export interface PlatformVersion extends Comparable<PlatformVersion>, Equals<PlatformVersion> {
    getVersion(): string;
}
